import{_ as a,o as l,c as r,a2 as i}from"./chunks/framework.BZO4qERu.js";const g=JSON.parse('{"title":"騎砍2 | 自立為王完全攻略：從流浪漢到一國之君","description":"","frontmatter":{},"headers":[],"relativePath":"bannerlord/kingdom-building.md","filePath":"bannerlord/kingdom-building.md"}'),o={name:"bannerlord/kingdom-building.md"};function e(n,t,s,h,d,p){return l(),r("div",null,[...t[0]||(t[0]=[i(`<h1 id="騎砍2-自立為王完全攻略-從流浪漢到一國之君" tabindex="-1">騎砍2 | 自立為王完全攻略：從流浪漢到一國之君 <a class="header-anchor" href="#騎砍2-自立為王完全攻略-從流浪漢到一國之君" aria-label="Permalink to &quot;騎砍2 | 自立為王完全攻略：從流浪漢到一國之君&quot;">​</a></h1><hr><h2 id="前言-想當國王-先問自己這三件事" tabindex="-1">前言：想當國王？先問自己這三件事 <a class="header-anchor" href="#前言-想當國王-先問自己這三件事" aria-label="Permalink to &quot;前言：想當國王？先問自己這三件事&quot;">​</a></h2><p>騎砍2最終極的目標就是——<strong>建立你自己的王國</strong>。</p><p>但在你腦中浮現「我要稱霸卡拉迪亞」的畫面時，先冷靜一下，問自己：</p><ol><li>我的家族等級到 3 了嗎？</li><li>我手下有至少 150 個精銳士兵嗎？</li><li>我口袋裡有至少 <strong>100 萬第納爾</strong> 嗎？</li></ol><p>如果以上有任一個答案是「沒有」，先把這篇存起來，回去練功。</p><p>如果都有了——恭喜你，可以開始看這篇了。</p><hr><h2 id="一、路線圖-從雇傭兵到國王" tabindex="-1">一、路線圖：從雇傭兵到國王 <a class="header-anchor" href="#一、路線圖-從雇傭兵到國王" aria-label="Permalink to &quot;一、路線圖：從雇傭兵到國王&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>雇傭兵 → 封臣 → 累積實力 → 脫離國家 → 宣布獨立 → 打下第一座城 → 建立王國</span></span>
<span class="line"><span>  ↑                                                            ↓</span></span>
<span class="line"><span>  └──────────── 被其他國家宣戰 ← 守住領土 ← 招募領主 ←────────┘</span></span></code></pre></div><hr><h2 id="二、第一階段-當封臣學經驗-家族等級-2-4" tabindex="-1">二、第一階段：當封臣學經驗（家族等級 2-4） <a class="header-anchor" href="#二、第一階段-當封臣學經驗-家族等級-2-4" aria-label="Permalink to &quot;二、第一階段：當封臣學經驗（家族等級 2-4）&quot;">​</a></h2><h3 id="為什麼不直接獨立" tabindex="-1">為什麼不直接獨立？ <a class="header-anchor" href="#為什麼不直接獨立" aria-label="Permalink to &quot;為什麼不直接獨立？&quot;">​</a></h3><p>因為你對這遊戲的國戰機制一無所知。</p><p><strong>先加入一個國家當封臣</strong>，你會學到：</p><ul><li>軍團怎麼召集</li><li>打仗勝負的影響</li><li>外交和投票系統</li><li>攻城需要多少準備</li><li>哪些領主好相處（之後可以挖角）</li></ul><h3 id="選哪個國家當封臣" tabindex="-1">選哪個國家當封臣？ <a class="header-anchor" href="#選哪個國家當封臣" aria-label="Permalink to &quot;選哪個國家當封臣？&quot;">​</a></h3><table tabindex="0"><thead><tr><th>國家</th><th>適合原因</th></tr></thead><tbody><tr><td>帝國（任一）</td><td>戰爭最多，實戰經驗值滿滿</td></tr><tr><td>瓦蘭迪亞</td><td>地圖角落，比較不會被多線夾攻</td></tr><tr><td>庫賽特</td><td>跟著強國混，勝率高</td></tr></tbody></table><blockquote><p>💡 建議選<strong>國力中等</strong>的國家。太強的你脫離後難打，太弱的可能還沒學到東西國家就亡了。</p></blockquote><h3 id="在封臣期間該做什麼" tabindex="-1">在封臣期間該做什麼？ <a class="header-anchor" href="#在封臣期間該做什麼" aria-label="Permalink to &quot;在封臣期間該做什麼？&quot;">​</a></h3><ul><li><strong>打仗</strong>：累積聲望，提升家族等級</li><li><strong>存錢</strong>：目標 100-200 萬第納爾</li><li><strong>練兵</strong>：把主力部隊練到頂級</li><li><strong>觀察</strong>：記下哪些領主對國王不滿（之後可以挖角）</li><li><strong>收集情報</strong>：了解各城市的守軍實力</li></ul><p>但在這之前，有一件事比當封臣更重要——</p><h3 id="⚡-前置策略-用雇傭兵身分削弱強國" tabindex="-1">⚡ 前置策略：用雇傭兵身分削弱強國 <a class="header-anchor" href="#⚡-前置策略-用雇傭兵身分削弱強國" aria-label="Permalink to &quot;⚡ 前置策略：用雇傭兵身分削弱強國&quot;">​</a></h3><p>在你正式當封臣之前，<strong>強烈建議先用雇傭兵的身分在大陸上攪局</strong>。</p><p>邏輯很簡單：</p><ol><li>你未來要自立，最大的威脅是什麼？不是某個國王討厭你，是<strong>某個國家已經統一了半張地圖</strong></li><li>雇傭兵的最大優勢是<strong>不會跟任何人變成敵人</strong>——你加入A國打B國，退出後B國不會恨你</li><li>所以你可以<strong>反覆橫跳</strong>：今天幫帝國打庫塞特，明天幫庫塞特打瓦蘭迪亞，後天幫瓦蘭迪亞打帝國</li><li>你的目標不是幫誰打贏，是<strong>確保沒有任何一國能獨大</strong></li></ol><blockquote><p>🧠 <strong>一句話：在自立之前，用雇傭兵身分當全大陸的「平衡器」。誰太強你就去打誰，打完就跳去另一邊。</strong></p></blockquote><p>這樣等你宣布獨立時，面對的是一個各國互相制衡的卡拉迪亞，而不是某個已經坐擁30座城的怪物。</p><p>關於雇傭兵戰略的更多細節，詳見 <a href="./beginner-guide.html">騎砍2 | 新手求生指南</a>。</p><hr><h2 id="三、第二階段-獨立宣言-關鍵時刻" tabindex="-1">三、第二階段：獨立宣言（關鍵時刻！） <a class="header-anchor" href="#三、第二階段-獨立宣言-關鍵時刻" aria-label="Permalink to &quot;三、第二階段：獨立宣言（關鍵時刻！）&quot;">​</a></h2><h3 id="時機判斷-✅" tabindex="-1">時機判斷 ✅ <a class="header-anchor" href="#時機判斷-✅" aria-label="Permalink to &quot;時機判斷 ✅&quot;">​</a></h3><p>以下條件<strong>至少滿足四個</strong>再考慮獨立：</p><ul><li>[ ] 家族等級 4 以上</li><li>[ ] 資金 100 萬第納爾以上</li><li>[ ] 精銳部隊 150+（不要用新兵湊數）</li><li>[ ] 至少有一位夥伴可以當領主</li><li>[ ] 你所在國家正在多線作戰（沒空理你）</li><li>[ ] 選定的第一個攻城目標防禦薄弱</li></ul><h3 id="脫離國家的方式" tabindex="-1">脫離國家的方式 <a class="header-anchor" href="#脫離國家的方式" aria-label="Permalink to &quot;脫離國家的方式&quot;">​</a></h3><p><strong>方式 A：和平分手（推薦）</strong></p><p>去王國介面，選擇「放棄封臣身分」→ 保留封地。</p><ul><li>✅ 不會立即開戰</li><li>❌ 你會失去原有封地</li></ul><p><strong>方式 B：帶封地叛逃（高風險）</strong></p><p>你身上有封地，直接跟國王說掰掰，把封地帶著走。</p><ul><li>✅ 直接有領地可以經營</li><li>❌ 原國家會<strong>立即對你宣戰</strong></li></ul><blockquote><p>⚠️ <strong>新手千萬別選 B</strong>，你會被碾過去。先和平分手，自己去打一座城比較安全。</p></blockquote><hr><h2 id="四、第三階段-打下第一座城-最難的一步" tabindex="-1">四、第三階段：打下第一座城（最難的一步） <a class="header-anchor" href="#四、第三階段-打下第一座城-最難的一步" aria-label="Permalink to &quot;四、第三階段：打下第一座城（最難的一步）&quot;">​</a></h2><h3 id="選對目標很重要" tabindex="-1">選對目標很重要 <a class="header-anchor" href="#選對目標很重要" aria-label="Permalink to &quot;選對目標很重要&quot;">​</a></h3><p><strong>好的攻城目標：</strong></p><ul><li>防守兵力少於 200 人</li><li>糧食儲備低（圍城時間短）</li><li>附近沒有敵方大軍</li></ul><p><strong>爛的攻城目標：</strong></p><ul><li>任何帝國內陸的大城（守軍多、援軍快）</li><li>跟多國接壤的城（一打下就被圍毆）</li></ul><h3 id="攻城流程" tabindex="-1">攻城流程 <a class="header-anchor" href="#攻城流程" aria-label="Permalink to &quot;攻城流程&quot;">​</a></h3><ol><li><strong>準備部隊</strong>：150+ 精兵，帶攻城器械</li><li><strong>包圍城市</strong>：圍城期間敵方糧食會消耗，守軍會減少</li><li><strong>建造器械</strong>：建造投石機、攻城塔</li><li><strong>總攻</strong>：器械建好後發起進攻</li><li><strong>拿下！</strong>：恭喜，你有第一座城了！</li></ol><blockquote><p>💡 圍城時注意地圖，如果有敵軍大部隊靠近，寧可先撤退也不要硬打。</p></blockquote><hr><h2 id="五、第四階段-建立王國" tabindex="-1">五、第四階段：建立王國 <a class="header-anchor" href="#五、第四階段-建立王國" aria-label="Permalink to &quot;五、第四階段：建立王國&quot;">​</a></h2><h3 id="設立王國" tabindex="-1">設立王國 <a class="header-anchor" href="#設立王國" aria-label="Permalink to &quot;設立王國&quot;">​</a></h3><p>佔領至少一座城/城堡後，打開家族介面 → 點「建立王國」。</p><p>系統會讓你：</p><ul><li>取國名（慎重，不能改）</li><li>選旗幟（慎重，不能改）</li><li>宣布獨立</li></ul><p>從這一刻起，你就是正式的國王了！</p><h3 id="立國後第一件大事-活下來" tabindex="-1">立國後第一件大事：活下來 <a class="header-anchor" href="#立國後第一件大事-活下來" aria-label="Permalink to &quot;立國後第一件大事：活下來&quot;">​</a></h3><p>新成立的王國 = <strong>全大陸的肥羊</strong>。</p><p><strong>生存策略：</strong></p><ol><li><strong>先防守，再擴張</strong>：不要急著打第二座城</li><li><strong>招募雇傭兵家族</strong>：去酒館找小陣營領袖，付錢讓他們幫你打仗</li><li><strong>挖角敵方領主</strong>：找對原國王不滿的領主，用錢說服他們加入你（超貴，但必須這麼做）</li><li><strong>求和</strong>：花錢跟交戰國停戰，一次只打一國</li></ol><hr><h2 id="六、第五階段-管理你的王國" tabindex="-1">六、第五階段：管理你的王國 <a class="header-anchor" href="#六、第五階段-管理你的王國" aria-label="Permalink to &quot;六、第五階段：管理你的王國&quot;">​</a></h2><h3 id="招募領主" tabindex="-1">招募領主 <a class="header-anchor" href="#招募領主" aria-label="Permalink to &quot;招募領主&quot;">​</a></h3><ul><li>跟領主對話 → 說服他們加入</li><li>需要高魅力值（或很多很多錢）</li><li>條件：領主必須對原國王不滿</li></ul><h3 id="頒布政策" tabindex="-1">頒布政策 <a class="header-anchor" href="#頒布政策" aria-label="Permalink to &quot;頒布政策&quot;">​</a></h3><table tabindex="0"><thead><tr><th>政策</th><th>效果</th></tr></thead><tbody><tr><td>元老院</td><td>增加領主忠誠度</td></tr><tr><td>土地稅</td><td>增加稅收</td></tr><tr><td>皇室衛隊</td><td>增加你個人的部隊上限</td></tr></tbody></table><blockquote><p>政策有好有壞，頒布前看清楚。</p></blockquote><h3 id="分配封地" tabindex="-1">分配封地 <a class="header-anchor" href="#分配封地" aria-label="Permalink to &quot;分配封地&quot;">​</a></h3><p>打下的城要分給領主，不然他們會不滿。</p><ul><li>第一座城自己留著</li><li>後續的新城分給新加入的領主</li><li>避免同一個領主有太多封地（太強會造反）</li></ul><hr><h2 id="🕳️-自立常見失敗原因" tabindex="-1">🕳️ 自立常見失敗原因 <a class="header-anchor" href="#🕳️-自立常見失敗原因" aria-label="Permalink to &quot;🕳️ 自立常見失敗原因&quot;">​</a></h2><table tabindex="0"><thead><tr><th>失敗原因</th><th>解法</th></tr></thead><tbody><tr><td>太早獨立，被聯軍輾過</td><td>存夠 100 萬和 150+ 精兵再獨立</td></tr><tr><td>沒領主幫忙，一人扛全線</td><td>獨立前就鎖定好要挖角的領主</td></tr><tr><td>經濟崩潰，兵跑光</td><td>確保工廠和商隊都在運作</td></tr><tr><td>打錯第一座城</td><td>選邊境小城，避開核心區</td></tr><tr><td>同時跟多國開戰</td><td>花錢求和，一次只打一國</td></tr></tbody></table><hr><h2 id="結語-建國不是結束-是開始" tabindex="-1">結語：建國不是結束，是開始 <a class="header-anchor" href="#結語-建國不是結束-是開始" aria-label="Permalink to &quot;結語：建國不是結束，是開始&quot;">​</a></h2><p>很多人以為立國就破關了，但其實立國之後才是真正的挑戰。</p><p>你要管理外交、經濟、領主關係、軍事部署……一個不小心，你辛辛苦苦建立的王國就可能土崩瓦解。</p><p>但這就是騎砍2最好玩的地方——<strong>你不是在玩一個遊戲，你是在活一段人生。</strong></p><p>祝你好運，未來的國王/女王陛下。🗡️</p><hr><h2 id="📖-相關攻略" tabindex="-1">📖 相關攻略 <a class="header-anchor" href="#📖-相關攻略" aria-label="Permalink to &quot;📖 相關攻略&quot;">​</a></h2><ul><li>還沒準備好建國？→ <a href="./money-making.html">騎砍2 | 賺錢密技</a></li><li>兵不夠強？→ <a href="./troop-tier-list.html">騎砍2 | 兵種大亂鬥</a></li><li>想裝 MOD 強化體驗？→ <a href="./mod-recommendations.html">騎砍2 | 2026 必裝 MOD 推薦</a></li></ul><hr><p><em>Blades Game 游刃攻略 — 遊刃有餘的遊戲攻略。全部原創內容，未經授權禁止轉載。</em></p><hr><h2 id="更新紀錄" tabindex="-1">更新紀錄 <a class="header-anchor" href="#更新紀錄" aria-label="Permalink to &quot;更新紀錄&quot;">​</a></h2><ul><li><strong>2026-06-11</strong>：文章建立。依據遊戲 v1.4.x 正式版撰寫。</li><li><strong>2026-06-11</strong>：新增「前置策略：用雇傭兵身分削弱強國」——在成為封臣前先用雇傭兵反覆橫跳，確保各國勢力均衡。</li></ul>`,91)])])}const b=a(o,[["render",e]]);export{g as __pageData,b as default};
